login()logout()updateProfile() <pre><code>const login = async (credentials: LoginCredentials) =&gt; {
  const response = await authApi.login(credentials);
  const { accessToken, refreshToken, user } = response.data;
  localStorage.setItem('accessToken', accessToken);
  localStorage.setItem('refreshToken', refreshToken);
  setState({ user, accessToken, isAuthenticated: true, isLoading: false });
};
</code></pre> <pre><code>const logout = async () =&gt; {
  try { await authApi.logout(); } catch {} // Ignore erreurs
  localStorage.removeItem('accessToken');
  localStorage.removeItem('refreshToken');
  setState({ user: null, accessToken: null, isAuthenticated: false, isLoading: false });
};
</code></pre> <pre><code>const updateProfile = async (data) =&gt; {
  const response = await authApi.updateMe(data);
  setState(prev =&gt; ({ ...prev, user: response.data }));
};
</code></pre>
